"use client";

import { useState } from "react";

export default function OrderTab({ orders }) {
    // ตัวอย่าง data สำหรับ order
    // orders = [
    //   { id: 1, name: "Be Nice Shower Cream", qty: 1, price: 109, status: "pending", image: "/images/products/showercream.png" },
    //   ...
    // ]

    const [orderList, setOrderList] = useState(orders);

    const handleReceive = (id) => {
        setOrderList(prev =>
            prev.map(order =>
                order.id === id ? { ...order, status: "received" } : order
            )
        );
    };

    return (
        <div className="space-y-6">
            {orderList.length > 0 ? (
                orderList.map(order => (
                    <div key={order.id} className="flex items-start space-x-4 pb-4 border-b">
                        <img src={order.image} alt={order.name} className="w-16 h-16 border rounded object-cover" />
                        <div className="flex-1">
                            <p className="text-sm font-medium">{order.name}</p>
                            <p className="text-xs text-gray-500">TotalProduct: {order.qty}</p>
                            <p className="text-xs mt-1">
                                Status:{" "}
                                <span className={`font-medium ${order.status === "pending" ? "text-green-600" : "text-orange-500"}`}>
                                    {order.status}
                                </span>
                            </p>
                        </div>
                        <div className="flex flex-col items-end justify-between">
                            <span className="font-semibold">${order.price}</span>
                            {order.status === "fulfilled" || order.status === "received" ? (
                                <button className="mt-2 px-3 py-1 text-xs bg-gray-200 rounded cursor-not-allowed">receive</button>
                            ) : (
                                <button onClick={() => handleReceive(order.id)} className="mt-2 px-3 py-1 text-xs bg-green-600 text-white rounded">
                                    receive
                                </button>
                            )}
                        </div>
                    </div>
                ))
            ) : (
                <div className="text-center text-gray-500 mt-10">
                    📦 No orders yet.
                </div>
            )}
        </div>
    );
}
